### SOPS Integration in Roko

```rust
/// Decrypt a SOPS-encrypted config file before parsing.
/// Falls back to plain-text parsing if the file is not SOPS-encrypted.
pub fn load_config_with_sops(path: &Path) -> Result<RokoConfig> {
    let content = std::fs::read_to_string(path)?;

    // Check if the file has SOPS metadata
    if content.contains("[sops]") || content.contains("\"sops\":") {
        // Decrypt via sops CLI
        let output = std::process::Command::new("sops")
            .args(["decrypt", &path.to_string_lossy()])
            .output()?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            anyhow::bail!("SOPS decryption failed: {stderr}");
        }

        let decrypted = String::from_utf8(output.stdout)?;
        Ok(toml::from_str(&decrypted)?)
    } else {
        // Plain-text config (no SOPS metadata)
        Ok(toml::from_str(&content)?)
    }
}
